6	export async function GET() {
7	  const tenant = await requireTenantContext();
8	  if (!tenant) {
9	    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
10	  }
11	
12	  const conclusions = await db.conclusion.findMany({
13	    where: {
14	      organizationId: tenant.organizationId,
15	      embeddingJson: { not: null },
16	    },
17	    select: {
18	      id: true,
19	      text: true,
20	      topicHint: true,
21	      confidenceTier: true,
22	      embeddingJson: true,
23	    },
24	    take: 2000,
25	  });
26	
27	  if (conclusions.length < 3) {
28	    return NextResponse.json({
29	      conclusions: [],
30	      axes: [],
31	      error:
32	        "Need at least 3 conclusions with embeddings for a projection. " +
33	        "Run the ingestion pipeline with the embedding bridge enabled to populate embeddings.",
34	    });
35	  }
36	
37	  const projection = computeProjection(conclusions);
38	  return NextResponse.json(projection);
39	}
