3	/** Request-scoped tenant identity (every authenticated portal request). */
4	export type TenantContext = {
5	  organizationId: string;
6	  organizationSlug: string;
7	  founderId: string;
8	  role: string;
9	};
10	
11	export async function requireTenantContext(): Promise<TenantContext | null> {
12	  const founder = await getFounder();
13	  if (!founder) return null;
14	  const slug = founder.organization?.slug ?? "";
15	  if (!slug) {
16	    throw new Error("Founder missing organization relation");
17	  }
18	  return {
19	    organizationId: founder.organizationId,
20	    organizationSlug: slug,
21	    founderId: founder.id,
22	    role: founder.role,
23	  };
24	}
