1	/**
2	 * PCA projection of conclusion embeddings onto a 2D plane.
3	 *
4	 * Deliberately from-scratch: the Codex only has tens to low-thousands
5	 * of conclusions per org, so a tiny in-process power-iteration PCA is
6	 * fine. No external linear algebra dependency.
7	 *
8	 * Strategy:
9	 *   1. Parse each conclusion's JSON embedding into a float[] of equal
10	 *      dimension D.
11	 *   2. Centre the matrix (subtract mean vector).
12	 *   3. Top-2 eigenvectors of the D×D covariance matrix via power
13	 *      iteration with Gram–Schmidt deflation.
14	 *   4. Project every row onto those eigenvectors.
15	 *   5. Label each axis by examining the topicHints at each pole.
16	 */
17	
18	export interface ProjectedConclusion {
19	  id: string;
20	  text: string;
21	  x: number;
22	  y: number;
23	  topicHint: string;
24	  confidenceTier: string;
25	}
26	
27	export interface SemanticAxis {
28	  index: number;
29	  label: string;
30	  varianceExplained: number;
31	  positivePole: string[];
32	  negativePole: string[];
33	}
34	
35	export interface EmbeddingProjection {
36	  conclusions: ProjectedConclusion[];
37	  axes: SemanticAxis[];
38	}
39	
40	export interface ConclusionWithEmbedding {
41	  id: string;
42	  text: string;
43	  topicHint: string;
44	  confidenceTier: string;
45	  embeddingJson: string | null;
46	}
47	
48	// ── Linear algebra helpers ──────────────────────────────────────────
49	
50	function dot(a: number[], b: number[]): number {
51	  let s = 0;
52	  for (let i = 0; i < a.length; i++) s += a[i] * b[i];
53	  return s;
54	}
55	
56	function scale(a: number[], s: number): number[] {
57	  return a.map((v) => v * s);
58	}
59	
60	function sub(a: number[], b: number[]): number[] {
61	  return a.map((v, i) => v - b[i]);
62	}
63	
64	function norm(a: number[]): number {
65	  return Math.sqrt(dot(a, a));
66	}
67	
68	function normalize(a: number[]): number[] {
69	  const n = norm(a);
70	  if (n === 0) return a;
71	  return scale(a, 1 / n);
72	}
73	
74	/**
75	 * Given the centred embedding matrix X (N×D), approximate the top
76	 * eigenvector of Xᵀ X via power iteration. We never materialise Xᵀ X
77	 * — we just apply it as a sequence of matrix-vector products.
78	 */
79	function topEigenvector(
80	  centered: number[][],
81	  init: number[],
82	  iterations = 40,
83	): { vec: number[]; eigenvalue: number } {
84	  const D = init.length;
85	  let v = normalize(init);
86	  for (let iter = 0; iter < iterations; iter++) {
87	    // w = X v  (length N)
88	    const w = centered.map((row) => dot(row, v));
89	    // u = Xᵀ w (length D)
90	    const u = new Array(D).fill(0) as number[];
91	    for (let i = 0; i < centered.length; i++) {
92	      const coeff = w[i];
93	      const row = centered[i];
94	      for (let j = 0; j < D; j++) u[j] += coeff * row[j];
95	    }
96	    const n = norm(u);
97	    if (n === 0) break;
98	    v = scale(u, 1 / n);
99	  }
100	  // Eigenvalue estimate via Rayleigh quotient: ‖X v‖²
101	  const Xv = centered.map((row) => dot(row, v));
102	  const eigenvalue = dot(Xv, Xv);
103	  return { vec: v, eigenvalue };
104	}
105	
106	// ── Public entry point ─────────────────────────────────────────────
107	
108	export function computeProjection(
109	  input: ConclusionWithEmbedding[],
110	): EmbeddingProjection {
111	  const parsed: {
